{
    "level": "B1",
    "intro": "W tym temacie nauczysz się używać <strong>collective nouns</strong> takich jak <strong>team, family, staff, police</strong> i poprawnie łączyć je z czasownikiem.",
    "rules": [
        {
            "label": "JEDNA GRUPA",
            "color": "emerald",
            "text": "Gdy grupa jest widziana jako <strong>jedna całość</strong>, często naturalny jest czasownik w liczbie pojedynczej.",
            "example": "The team is ready."
        },
        {
            "label": "CZŁONKOWIE",
            "color": "blue",
            "text": "Gdy skupiasz się na <strong>osobach wewnątrz grupy</strong>, zwłaszcza w BrE, możliwa jest liczba mnoga.",
            "example": "The team are wearing different shirts."
        },
        {
            "label": "SZCZEGÓLNE PRZYPADKI",
            "color": "amber",
            "text": "Niektóre słowa mają własny schemat: <strong>police</strong> prawie zawsze łączy się z liczbą mnogą.",
            "example": "The police are investigating the case."
        }
    ]
}

{
    "title": "1. Częste collective nouns",
    "intro": "Zapamiętaj typowe słowa i ich zachowanie.",
    "items": [
        {
            "label": "często liczba pojedyncza",
            "title": "team / family / class / committee",
            "subtitle": "The family is happy."
        },
        {
            "label": "pojedyncza albo mnoga",
            "title": "staff / audience / government",
            "subtitle": "zależy od znaczenia i odmiany angielskiego"
        },
        {
            "label": "zwykle liczba mnoga",
            "title": "police",
            "subtitle": "The police are here."
        },
        {
            "label": "znaczenie decyduje",
            "title": "couple / crew / company",
            "subtitle": "jedna całość czy oddzielni członkowie?"
        }
    ]
}

{
    "title": "2. Jak wybrać formę",
    "sections": [
        {
            "label": "Grupa jako jedna całość",
            "color": "emerald",
            "description": "Gdy mówisz o grupie jako <strong>jednej jednostce</strong>, naturalnie brzmi liczba pojedyncza.",
            "examples": [
                {
                    "en": "The team is ready for the match.",
                    "ua": "Drużyna jest gotowa do meczu."
                },
                {
                    "en": "My family lives in Lviv.",
                    "ua": "Moja rodzina mieszka we Lwowie."
                },
                {
                    "en": "The committee has made its decision.",
                    "ua": "Komitet podjął swoją decyzję."
                }
            ]
        },
        {
            "label": "Członkowie osobno",
            "color": "blue",
            "description": "W brytyjskim angielskim liczba mnoga jest możliwa, gdy nacisk pada na <strong>ludzi wewnątrz grupy</strong>.",
            "examples": [
                {
                    "en": "The team are wearing different shirts.",
                    "ua": "Członkowie drużyny mają różne koszulki."
                },
                {
                    "en": "My family are all coming at different times.",
                    "ua": "Wszyscy członkowie mojej rodziny przyjeżdżają o różnych porach."
                },
                {
                    "en": "The staff are arguing about the schedule.",
                    "ua": "Pracownicy kłócą się o grafik."
                }
            ],
            "note": "W amerykańskim angielskim w takich przypadkach częściej zostaje liczba pojedyncza."
        },
        {
            "label": "Szczególne przypadki",
            "color": "amber",
            "description": "<strong>Police</strong> prawie zawsze łączy się z liczbą mnogą; inne rzeczowniki zależą od znaczenia.",
            "examples": [
                {
                    "en": "The police are outside.",
                    "ua": "Policja jest na zewnątrz."
                },
                {
                    "en": "The audience was silent.",
                    "ua": "Publiczność była cicho."
                },
                {
                    "en": "The audience were taking their seats.",
                    "ua": "Ludzie na widowni zajmowali miejsca."
                }
            ],
            "note": "Ten sam rzeczownik może przyjmować różne uzgodnienie zależnie od tego, co chcesz podkreślić."
        }
    ]
}

{
    "title": "3. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Police z liczbą pojedynczą.",
            "wrong": "The police is here.",
            "right": "✅ <span class=\"font-mono\">The police are here.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Automatyczna liczba mnoga dla wszystkich collective nouns.",
            "wrong": "My family are small. <span class=\"text-slate-500\">(jeśli chodzi o rodzinę jako jedną całość)</span>",
            "right": "✅ <span class=\"font-mono\">My family is small.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Ignorowanie znaczenia.",
            "wrong": "The team is wearing different shirts. <span class=\"text-slate-500\">(jeśli nacisk pada na zawodników osobno)</span>",
            "right": "✅ <span class=\"font-mono\">The team are wearing different shirts.</span>"
        }
    ]
}

{
    "title": "4. Krótkie podsumowanie",
    "items": [
        "Collective nouns nazywają grupę ludzi albo rzeczy jako jedną jednostkę.",
        "Liczba pojedyncza pasuje, gdy grupa jest postrzegana jako całość.",
        "Liczba mnoga jest możliwa, gdy ważni są poszczególni członkowie, zwłaszcza w BrE.",
        "<strong>Police</strong> zwykle łączy się z liczbą mnogą.",
        "Właściwy wybór zależy nie tylko od rzeczownika, ale też od znaczenia w zdaniu."
    ]
}

